CREATE DEFINER=`mysql`@`%` PROCEDURE `open_current_account`()
begin
   declare id_code bigint;
   declare next_account_number bigint;
   declare ac_count integer;
   declare done boolean default false;
   declare customer_cursor CURSOR for select idcode from customer;
   declare continue handler for not found set done = True;
      
   open customer_cursor;
   
   read_loop: loop
       fetch customer_cursor into id_code;
       
       if done then 
           leave read_loop;
	   end if;
   
       select count(*) into ac_count from account where customerid = id_code and accounttype = 'CURR';
       if ac_count = 0 then
           select max(accountnumber) + 1 into next_account_number from account;
           values (next_account_number, id_code, 'CURR');
       end if;
   end loop;
   
   close customer_cursor;
end ;;
DELIMITER ;
